insert into public.tricks (name, category, history, inventor, year, youtube_query) values
('Ollie', 'flatground', 'The foundational trick of modern skateboarding, invented by Alan Gelfand on vert in 1977 and adapted to flatground by Rodney Mullen in 1982. It allows the skater to leap into the air without using their hands.', 'Alan ''Ollie'' Gelfand', 1977, 'how to ollie skateboard tutorial beginner'),
('Kickflip', 'flatground', 'Invented by Rodney Mullen in 1983, originally called the ''magic flip.'' The skater flicks the board with their front foot to make it rotate along its length axis. It became the most iconic trick in street skating.', 'Rodney Mullen', 1983, 'how to kickflip skateboard tutorial'),
('Heelflip', 'flatground', 'Invented by Rodney Mullen in 1983 alongside the kickflip. The skater flicks the board with their heel to spin it in the opposite direction of a kickflip.', 'Rodney Mullen', 1983, 'how to heelflip skateboard tutorial'),
('Hardflip', 'flatground', 'A combination of a frontside pop shove-it and a kickflip. The board rotates in opposite directions simultaneously, making it one of the more technical flatground tricks.', null, null, 'how to hardflip skateboard tutorial'),
('Inward Heelflip', 'flatground', 'A combination of a backside pop shove-it and a heelflip. The board flips and rotates simultaneously in directions that work against each other.', null, null, 'how to inward heelflip skateboard tutorial'),
('Pop Shove-it', 'flatground', 'An ollie combined with a 180-degree backside rotation of the board while the skater''s body stays facing forward. A foundational street trick.', null, null, 'how to pop shove it skateboard tutorial'),
('Frontside Pop Shove-it', 'flatground', 'Similar to the pop shove-it but the board rotates in the frontside direction. Often considered harder to control than the backside version.', null, null, 'how to frontside pop shove it skateboard tutorial'),
('360 Flip', 'flatground', 'Also known as a tre flip or 3 flip, invented by Rodney Mullen. Combines a 360-degree backside pop shove-it with a kickflip simultaneously. One of the most revered street tricks.', 'Rodney Mullen', 1984, 'how to 360 flip tre flip skateboard tutorial'),
('360 Hardflip', 'flatground', 'A combination of a frontside 360 shove-it and a kickflip. Considered one of the most technical flatground flip tricks due to the opposing rotations.', null, null, 'how to 360 hardflip skateboard tutorial'),
('Varial Kickflip', 'flatground', 'A combination of a backside pop shove-it and a kickflip performed simultaneously. A staple intermediate trick popularized in the early 1990s street skating scene.', null, null, 'how to varial kickflip skateboard tutorial'),
('Varial Heelflip', 'flatground', 'Combines a frontside pop shove-it with a heelflip. The board rotates and flips in complementary directions.', null, null, 'how to varial heelflip skateboard tutorial'),
('Double Kickflip', 'flatground', 'A kickflip where the board completes two full rotations before the skater catches it. Requires significant height and precise flicking technique.', null, null, 'how to double kickflip skateboard tutorial'),
('Double Heelflip', 'flatground', 'A heelflip with two full rotations. Notoriously difficult to control due to the wide arc of the heel flick.', null, null, 'how to double heelflip skateboard tutorial'),
('Triple Kickflip', 'flatground', 'Three full kickflip rotations before landing. Extremely rare in practice and requires very high ollies to complete.', null, null, 'triple kickflip skateboard'),
('Laser Flip', 'flatground', 'A frontside 360 shove-it combined with a heelflip. Considered one of the hardest single-board-flip tricks due to the opposing rotation directions.', null, null, 'how to laser flip skateboard tutorial'),
('Dolphin Flip', 'flatground', 'A forward flip (frontside vertical flip) combined with a frontside pop shove-it. The board flips nose-down in a unique motion rarely seen in competitions.', null, null, 'dolphin flip skateboard tutorial'),
('Nollie', 'flatground', 'An ollie performed from the nose of the board by popping the nose and sliding the back foot up. Named as a combination of ''nose'' and ''ollie.''', null, null, 'how to nollie skateboard tutorial'),
('Nollie Kickflip', 'flatground', 'A kickflip executed from the nollie stance, where the back foot does the flicking motion. Requires rethinking body mechanics relative to a regular kickflip.', null, null, 'how to nollie kickflip skateboard tutorial'),
('Nollie Heelflip', 'flatground', 'A heelflip from nollie stance. The front foot pops the nose while the back foot flicks the board heel-side.', null, null, 'how to nollie heelflip skateboard tutorial'),
('Nollie 360 Flip', 'flatground', 'A 360 flip performed from nollie stance. One of the more difficult nollie tricks due to the complexity of the combined rotations.', null, null, 'how to nollie 360 flip skateboard tutorial'),
('Nollie Hardflip', 'flatground', 'A hardflip from nollie stance, combining a nollie frontside shove-it with a nollie kickflip. An advanced nollie trick.', null, null, 'nollie hardflip skateboard tutorial'),
('Nollie Inward Heelflip', 'flatground', 'An inward heelflip from nollie stance. Among the rarest nollie flip combinations.', null, null, 'nollie inward heelflip skateboard'),
('Fakie Ollie', 'flatground', 'An ollie performed while rolling in fakie (backwards) stance. The mechanics are inverted compared to a regular ollie.', null, null, 'how to fakie ollie skateboard tutorial'),
('Fakie Kickflip', 'flatground', 'A kickflip from fakie stance. Because the skater is rolling backward, the foot positioning and flick direction feel counterintuitive.', null, null, 'how to fakie kickflip skateboard tutorial'),
('Fakie Heelflip', 'flatground', 'A heelflip performed while rolling fakie. The back foot executes the heel flick while the front foot pops.', null, null, 'how to fakie heelflip skateboard tutorial'),
('Fakie 360 Flip', 'flatground', 'A 360 flip from fakie stance. Can feel more natural than a regular tre flip for some skaters due to the body rotation alignment.', null, null, 'how to fakie 360 flip skateboard tutorial'),
('Fakie Hardflip', 'flatground', 'A hardflip executed from fakie stance. The inversion of stance creates unique challenges for body and board coordination.', null, null, 'fakie hardflip skateboard tutorial'),
('Switch Ollie', 'flatground', 'An ollie performed in switch stance, meaning the skater''s non-dominant foot is at the back. First popularized in the early 1990s as skating progressed.', null, null, 'how to switch ollie skateboard tutorial'),
('Switch Kickflip', 'flatground', 'A kickflip in switch stance. Requires completely rebuilding muscle memory because the dominant foot is now at the front.', null, null, 'how to switch kickflip skateboard tutorial'),
('Switch Heelflip', 'flatground', 'A heelflip in switch stance. One of the benchmarks for all-around technical ability in modern street skating.', null, null, 'how to switch heelflip skateboard tutorial'),
('Switch 360 Flip', 'flatground', 'A 360 flip performed in switch stance. Considered a pinnacle of flatground technical skating and seen in the parts of elite pros.', null, null, 'switch 360 flip skateboard tutorial'),
('Switch Hardflip', 'flatground', 'A hardflip in switch stance. Extremely rare in skateboarding and requires mastery of both the switch stance and the hardflip.', null, null, 'switch hardflip skateboard'),
('Frontside 180', 'flatground', 'An ollie combined with a 180-degree frontside body rotation. A foundational trick connecting flatground skating to ledge and rail tricks.', null, null, 'how to frontside 180 skateboard tutorial'),
('Backside 180', 'flatground', 'An ollie with a 180-degree backside body rotation. Often one of the first spin tricks skaters learn after mastering the ollie.', null, null, 'how to backside 180 skateboard tutorial'),
('Frontside 360', 'flatground', 'A full 360-degree frontside body rotation combined with an ollie. Requires significant commitment and pop to complete the full rotation.', null, null, 'how to frontside 360 skateboard tutorial'),
('Backside 360', 'flatground', 'A full 360-degree backside body rotation with an ollie. One of the most crowd-pleasing flatground tricks when done with style.', null, null, 'how to backside 360 skateboard tutorial'),
('Frontside 180 Kickflip', 'flatground', 'Combines a frontside 180 body rotation with a kickflip. Also called a ''frontside kickflip'' in casual usage. A classic technical trick.', null, null, 'how to frontside 180 kickflip skateboard tutorial'),
('Backside 180 Kickflip', 'flatground', 'Combines a backside 180 body rotation with a kickflip. A staple of intermediate and advanced street skating.', null, null, 'how to backside 180 kickflip skateboard tutorial'),
('Frontside 180 Heelflip', 'flatground', 'A heelflip combined with a frontside 180 body rotation. Less common than its kickflip counterpart but equally technical.', null, null, 'how to frontside 180 heelflip skateboard tutorial'),
('Backside 180 Heelflip', 'flatground', 'A heelflip with a backside 180 body rotation. Considered one of the cleaner-looking flip combinations.', null, null, 'how to backside 180 heelflip skateboard tutorial'),
('Nollie Backside 180', 'flatground', 'A backside 180 performed from nollie stance. The body rotates backside while the nose is popped.', null, null, 'nollie backside 180 skateboard tutorial'),
('Nollie Frontside 180', 'flatground', 'A frontside 180 from nollie stance, creating a unique visual effect as the skater spins off the nose.', null, null, 'nollie frontside 180 skateboard tutorial'),
('Fakie Frontside 180', 'flatground', 'A frontside 180 from fakie stance. Landing back in regular stance, it is sometimes called a ''fakie frontside half-cab.''', null, null, 'fakie frontside 180 skateboard tutorial'),
('Half Cab', 'flatground', 'A fakie backside 180 (landing in regular). Named after Steve Caballero, who invented the full Caballerial (fakie 360). A classic foundational trick.', 'Steve Caballero', 1983, 'how to half cab skateboard tutorial'),
('Caballerial', 'vert', 'A fakie 360 ollie invented by Steve Caballero on vert in 1981. One of the most celebrated tricks of the early 1980s vert skating era.', 'Steve Caballero', 1981, 'caballerial skateboard vert trick'),
('Impossible', 'flatground', 'Invented by Rodney Mullen, the board wraps 360 degrees around the back foot vertically. Originally considered literally impossible to land, hence the name.', 'Rodney Mullen', 1982, 'how to impossible skateboard tutorial'),
('Nollie Impossible', 'flatground', 'An impossible performed from nollie stance, with the board wrapping around the front foot. Extremely rare in street skating.', null, null, 'nollie impossible skateboard tutorial'),
('Fakie Impossible', 'flatground', 'An impossible from fakie stance. The board wraps around the foot while rolling backward, creating a unique challenge.', null, null, 'fakie impossible skateboard tutorial'),
('Pressure Flip', 'flatground', 'A trick where the back foot applies pressure to pop the board into a frontside flip without a true ollie. Associated with the early 1990s and Daewon Song.', null, null, 'pressure flip skateboard tutorial'),
('Forward Flip', 'flatground', 'The board flips in a forward/upward direction (nose goes down first) rather than the standard kickflip motion. A rare and stylistically unusual trick.', null, null, 'forward flip skateboard trick'),
('Gazelle Flip', 'flatground', 'A backside 540 body rotation with a kickflip. An advanced and rare trick combining extreme body rotation with a board flip.', null, null, 'gazelle flip skateboard tutorial'),
('Gazelle Spin', 'flatground', 'A backside 540-degree body rotation with a 360 backside board rotation. Originally a freestyle trick brought into street skating.', 'Rodney Mullen', 1984, 'gazelle spin skateboard freestyle'),
('Hospital Flip', 'flatground', 'The back foot scoops forward (instead of backward) causing the board to flip in a unique motion. Also called a ''finger flip on the ground.''', null, null, 'hospital flip skateboard tutorial'),
('Primo Flip', 'flatground', 'The board is balanced on its side (primo position) and then flipped back to normal. A freestyle-derived trick adapted into street skating.', null, null, 'primo flip skateboard tutorial'),
('Casper Flip', 'flatground', 'Named after Bobby ''Casper'' Boyden. The board goes through a half-flip into a Casper stall position then flips back to normal. A classic freestyle trick.', 'Bobby Boyden', 1975, 'casper flip skateboard tutorial'),
('Fingerflip', 'flatground', 'The rider uses their fingers to flip the board during an ollie. Originally a vert/old school trick adapted to street skating.', null, null, 'finger flip skateboard tutorial'),
('Airwalk', 'flatground', 'The rider kicks both feet out to the sides while airborne, as if walking in the air. Originally a vert trick popularized by Tony Hawk.', 'Tony Hawk', 1983, 'airwalk skateboard trick tutorial'),
('No Comply', 'flatground', 'The front foot steps off the board as the back foot pops it, then the front foot lands back on. A foundational old school trick popularized by Neil Blender.', 'Neil Blender', 1986, 'how to no comply skateboard tutorial'),
('No Comply 180', 'flatground', 'A no comply combined with a 180-degree board rotation. A stylish old-school-influenced trick popular in modern creative skating.', null, null, 'no comply 180 skateboard tutorial'),
('No Comply 360', 'flatground', 'A no comply with a full 360-degree board rotation. Requires significant timing and coordination between the stepping foot and the spinning board.', null, null, 'no comply 360 skateboard tutorial'),
('No Comply Kickflip', 'flatground', 'A no comply where the board is also kickflipped. Combines the stepping-off motion with a flip trick for a uniquely stylish result.', null, null, 'no comply kickflip skateboard tutorial'),
('Body Varial', 'flatground', 'The skater rotates their body 180 degrees while the board does not rotate. Creates a switch or fakie landing without changing the board''s direction.', null, null, 'body varial skateboard tutorial'),
('Ollie North', 'flatground', 'After an ollie, the front foot is kicked forward off the nose of the board, then returned. A stylish old-school flatground trick.', null, null, 'ollie north skateboard tutorial'),
('Ollie South', 'flatground', 'After an ollie, the back foot kicks off the tail of the board while airborne, then returns. The counterpart to the Ollie North.', null, null, 'ollie south skateboard trick'),
('Disco Flip', 'flatground', 'A fakie 360 flip (or sometimes used to describe a hardflip variant). The term is used inconsistently in different regions of the skateboarding world.', null, null, 'disco flip skateboard tutorial'),
('540 Flip', 'flatground', 'A kickflip combined with a 540-degree backside board rotation. An extremely difficult flatground trick rarely landed cleanly.', null, null, '540 flip skateboard tutorial'),
('Big Flip', 'flatground', 'A backside 360 body rotation combined with a kickflip. The board and body rotate in the same direction, creating a flowing visual.', null, null, 'how to big flip skateboard tutorial'),
('Big Spin', 'flatground', 'A backside 360 body rotation combined with a backside 360 board rotation (pop shove-it). A stylish intermediate-level spinning trick.', null, null, 'how to big spin skateboard tutorial'),
('Frontside Big Spin', 'flatground', 'A frontside 360 body rotation with a frontside 360 shove-it. The frontside version of the big spin.', null, null, 'frontside big spin skateboard tutorial'),
('Nollie Big Spin', 'flatground', 'A big spin performed from nollie stance. The complexity of combining nollie with the full rotation makes this a rare trick.', null, null, 'nollie big spin skateboard tutorial'),
('Fakie Big Spin', 'flatground', 'A big spin from fakie stance. Since the skater is already rolling backward, the rotation dynamics feel different.', null, null, 'fakie big spin skateboard tutorial'),
('Bigspin Kickflip', 'flatground', 'A big spin (backside 360 body and board) combined with a kickflip. An extremely rare and technical combination trick.', null, null, 'bigspin kickflip skateboard'),
('Ghetto Bird', 'flatground', 'A backside 180 kickflip where the skater rotates backside and the board kickflips simultaneously. Popularized by Kareem Campbell.', 'Kareem Campbell', 1995, 'how to ghetto bird skateboard tutorial'),
('Nollie Varial Kickflip', 'flatground', 'A varial kickflip from nollie stance. The board shove-its backside while kickflipping from the nollie position.', null, null, 'nollie varial kickflip skateboard tutorial'),
('Fakie Varial Kickflip', 'flatground', 'A varial kickflip from fakie stance. A reliable intermediate-level fakie trick.', null, null, 'fakie varial kickflip skateboard tutorial'),
('Fakie Varial Heelflip', 'flatground', 'A varial heelflip from fakie stance. Combines the fakie shove-it with the heel flick for an advanced fakie combination.', null, null, 'fakie varial heelflip skateboard tutorial'),
('Nollie Varial Heelflip', 'flatground', 'A varial heelflip from nollie stance. One of the more obscure nollie combinations.', null, null, 'nollie varial heelflip skateboard'),
('360 Inward Heelflip', 'flatground', 'An inward heelflip with a 360-degree body rotation added. Combines the complexity of the inward heel with a full spin.', null, null, '360 inward heelflip skateboard'),
('Muska Flip', 'flatground', 'A frontside 180 kickflip performed in a smooth, stylish manner associated with Chad Muska. The term is informal and refers to his signature style.', 'Chad Muska', 1998, 'frontside 180 kickflip muska flip skateboard'),
('50-50 Grind', 'street', 'Both trucks grind along a rail or ledge simultaneously. One of the most fundamental grind tricks and a cornerstone of street and ledge skating.', null, null, 'how to 50-50 grind skateboard tutorial'),
('5-0 Grind', 'street', 'Only the back truck grinds the obstacle while the front is raised. The name comes from the nose being elevated at a ''5 o''clock'' angle.', null, null, 'how to 5-0 grind skateboard tutorial'),
('Nosegrind', 'street', 'The front truck grinds on the obstacle while the back truck is elevated. The counterpart to the 5-0 and a staple of ledge and rail skating.', null, null, 'how to nosegrind skateboard tutorial'),
('Crooked Grind', 'street', 'Also called a K-grind. The front truck grinds while the board is angled so the nose points down into or across the obstacle. A highly technical grind.', null, null, 'how to crooked grind skateboard tutorial'),
('Salad Grind', 'street', 'The back truck grinds while the board is tilted at an angle (frontside). A stylish variation between a 5-0 and a boardslide.', null, null, 'how to salad grind skateboard tutorial'),
('Overcrook', 'street', 'A crooked grind where the nose points upward past the ledge and the front truck grinds on the far side. The board goes ''over'' the obstacle.', null, null, 'how to overcrook grind skateboard tutorial'),
('Feeble Grind', 'street', 'The back truck grinds while the front truck hangs over on the far side of the obstacle (usually a rail). A fundamental rail trick.', null, null, 'how to feeble grind skateboard tutorial'),
('Smith Grind', 'street', 'The back truck grinds the obstacle while the front truck hangs below and the board is angled. Named after Mike Smith who invented it in the early 1980s.', 'Mike Smith', 1982, 'how to smith grind skateboard tutorial'),
('Willy Grind', 'street', 'A grind where only the back truck makes contact and the board is nearly parallel to the obstacle, creating a unique angled position. Named after Willy Santos.', 'Willy Santos', 1996, 'willy grind skateboard tutorial'),
('Nose Blunt Grind', 'street', 'The nose of the board presses against the top of the obstacle while grinding, with the front truck locked on. A difficult stall-grind hybrid.', null, null, 'nose blunt grind skateboard tutorial'),
('Blunt Grind', 'street', 'The tail of the board presses against the obstacle while the back truck grinds. Involves the tail making contact with the top surface.', null, null, 'blunt grind skateboard tutorial'),
('Axle Stall', 'street', 'Both trucks come to a complete stop on top of an obstacle, then the skater drops back in. A foundational transition and ledge trick.', null, null, 'how to axle stall skateboard tutorial'),
('Nosestall', 'street', 'The front truck stalls on the edge of an obstacle. Often used as a setup for other tricks or as a stylish pause in a line.', null, null, 'how to nosestall skateboard tutorial'),
('Tailstall', 'street', 'The tail of the board stalls on the edge of an obstacle. A simple but effective trick used in transition and street skating.', null, null, 'how to tailstall skateboard tutorial'),
('Boardslide', 'street', 'The board slides perpendicular to the obstacle (rail or ledge) with the middle of the board on the surface. A fundamental slide trick in street skating.', null, null, 'how to boardslide skateboard tutorial'),
('Frontside Boardslide', 'street', 'A boardslide where the skater approaches frontside (chest facing the obstacle). Considered slightly more accessible than the backside version.', null, null, 'how to frontside boardslide skateboard tutorial'),
('Backside Boardslide', 'street', 'A boardslide approached from the backside (back facing the obstacle). Requires blind commitment which makes it trickier to learn.', null, null, 'how to backside boardslide skateboard tutorial'),
('Noseslide', 'street', 'The nose of the board slides along the obstacle while the tail is elevated. A very stylish and technical ledge trick.', null, null, 'how to noseslide skateboard tutorial'),
('Tailslide', 'street', 'The tail of the board slides on the obstacle while the nose is elevated. Can be done frontside or backside.', null, null, 'how to tailslide skateboard tutorial'),
('Lipslide', 'street', 'The board slides over the obstacle with the tail leading (opposite of a boardslide approach). The skater ollies over the obstacle and comes down on it sideways.', null, null, 'how to lipslide skateboard tutorial'),
('Frontside Lipslide', 'street', 'A lipslide approached from the frontside, requiring the skater to ollie over the rail/ledge frontside.', null, null, 'how to frontside lipslide skateboard tutorial'),
('Backside Lipslide', 'street', 'A lipslide approached from the backside. The skater must ollie over the rail and come down on it from behind.', null, null, 'how to backside lipslide skateboard tutorial'),
('Darkslide', 'street', 'Invented by Rodney Mullen, the board is flipped upside down so the grip tape slides along the obstacle. One of the most iconic and technical slide tricks ever created.', 'Rodney Mullen', 1995, 'darkslide skateboard trick tutorial'),
('Gazelle Grind', 'street', 'A 540-degree body rotation combined with a grind on an obstacle. An extremely rare and advanced combination trick.', null, null, 'gazelle grind skateboard trick'),
('Switch Crooked Grind', 'street', 'A crooked grind performed in switch stance. Adds significant difficulty to an already technical grind.', null, null, 'switch crooked grind skateboard'),
('Nollie Crooked Grind', 'street', 'A crooked grind entered from nollie stance. The nose is popped to enter the grind.', null, null, 'nollie crooked grind skateboard'),
('Switch 50-50', 'street', 'A 50-50 grind performed in switch stance. Both trucks grind while the skater rides in their non-dominant direction.', null, null, 'switch 50-50 grind skateboard tutorial'),
('Switch Nosegrind', 'street', 'A nosegrind in switch stance. The front truck (now the weaker foot''s side) grinds on the obstacle.', null, null, 'switch nosegrind skateboard tutorial'),
('Switch Smith Grind', 'street', 'A Smith grind performed in switch stance. A significantly advanced version of the already technical Smith grind.', null, null, 'switch smith grind skateboard tutorial'),
('Switch Feeble Grind', 'street', 'A feeble grind in switch stance. The back truck (weaker side) hangs on the far side of the rail while grinding.', null, null, 'switch feeble grind skateboard'),
('Kickflip 50-50', 'street', 'A kickflip into a 50-50 grind. The board flips before landing in the grind position. A popular trick in tech street skating.', null, null, 'kickflip 50-50 skateboard tutorial'),
('Heelflip Nosegrind', 'street', 'A heelflip that lands into a nosegrind. Requires precise flick and catch to enter the grind cleanly.', null, null, 'heelflip nosegrind skateboard tutorial'),
('Kickflip Nosegrind', 'street', 'A kickflip entry into a nosegrind. A technical ledge trick combining a flip trick with the precision of the nosegrind.', null, null, 'kickflip nosegrind skateboard tutorial'),
('Noseblunt Slide', 'street', 'The nose of the board digs into the top of the obstacle while sliding. An extremely technical ledge trick requiring perfect approach.', null, null, 'how to noseblunt slide skateboard tutorial'),
('Blunt Slide', 'street', 'The tail of the board slides on the obstacle while stalled at an angle. A classic ledge trick combining the blunt stall with forward momentum.', null, null, 'how to blunt slide skateboard tutorial'),
('Heelflip Boardslide', 'street', 'A heelflip into a boardslide position. Requires the board to be caught sideways after the heel flip rotation.', null, null, 'heelflip boardslide skateboard tutorial'),
('Kickflip Boardslide', 'street', 'A kickflip into a boardslide. One of the classic tech ledge tricks.', null, null, 'kickflip boardslide skateboard tutorial'),
('Hardflip Nosegrind', 'street', 'A hardflip into a nosegrind. An extremely technical combination rarely attempted.', null, null, 'hardflip nosegrind skateboard'),
('Frontside Noseslide', 'street', 'A noseslide entered from the frontside. The skater''s chest faces the obstacle during the slide.', null, null, 'how to frontside noseslide skateboard tutorial'),
('Backside Noseslide', 'street', 'A noseslide entered from the backside. The skater''s back faces the obstacle during the slide.', null, null, 'how to backside noseslide skateboard tutorial'),
('Frontside Tailslide', 'street', 'A tailslide where the approach is frontside. A highly stylish trick when done on long ledges.', null, null, 'how to frontside tailslide skateboard tutorial'),
('Backside Tailslide', 'street', 'A tailslide approached from the backside. Considered more difficult due to the blind commitment required.', null, null, 'how to backside tailslide skateboard tutorial'),
('Nosegrind to Tailslide', 'street', 'A nosegrind that transitions into a tailslide mid-obstacle. An advanced ledge line trick requiring body repositioning during the trick.', null, null, 'nosegrind to tailslide skateboard'),
('5-0 to Fakie', 'street', 'A 5-0 grind that exits by rolling backward in fakie. A smooth and stylish exit from a grind used on ledges and curbs.', null, null, '5-0 to fakie skateboard tutorial'),
('Nosegrind to Fakie', 'street', 'A nosegrind that exits rolling fakie. A clean technical finish to a nosegrind.', null, null, 'nosegrind to fakie skateboard tutorial'),
('Boardslide to Fakie', 'street', 'A boardslide that exits fakie (rolling backward). A popular slide exit when going from the middle of a rail.', null, null, 'boardslide to fakie skateboard tutorial'),
('Hurricane Grind', 'street', 'The back truck grinds backside while the nose pivots around and the front truck swings out to the backside. A classic grind combination.', null, null, 'how to hurricane grind skateboard tutorial'),
('Frontside Hurricane', 'street', 'A hurricane grind entered from the frontside. Less common than the backside version and requires different approach mechanics.', null, null, 'frontside hurricane grind skateboard tutorial'),
('Pivot Fakie', 'street', 'The tail stalls on an obstacle and the board pivots 180 degrees to exit fakie. A foundational trick in both street and transition skating.', null, null, 'how to pivot fakie skateboard tutorial'),
('Nosepick', 'street', 'The nose of the board locks on the corner of an obstacle while the back end is lifted. A stylish stall trick.', null, null, 'nosepick skateboard trick tutorial'),
('Tailpick', 'street', 'The tail picks on the corner of an obstacle while the nose is elevated. The counterpart to the nosepick.', null, null, 'tailpick skateboard trick tutorial'),
('Switch Boardslide', 'street', 'A boardslide performed in switch stance. The approach and body mechanics are reversed compared to the regular boardslide.', null, null, 'switch boardslide skateboard tutorial'),
('Switch Noseslide', 'street', 'A noseslide in switch stance. A highly coveted tech slide trick.', null, null, 'switch noseslide skateboard tutorial'),
('Switch Tailslide', 'street', 'A tailslide performed in switch stance. Considered one of the harder switch slide tricks.', null, null, 'switch tailslide skateboard tutorial'),
('Nollie Noseslide', 'street', 'A noseslide entered from nollie stance. The nose is popped while approaching the obstacle.', null, null, 'nollie noseslide skateboard tutorial'),
('Nollie Tailslide', 'street', 'A tailslide entered from nollie stance. The nollie pop launches the skater into the slide position.', null, null, 'nollie tailslide skateboard tutorial'),
('Halfcab Noseslide', 'street', 'A half-cab (fakie backside 180) into a noseslide. A creative combination merging the spin entry with the technical slide.', null, null, 'halfcab noseslide skateboard tutorial'),
('Halfcab Boardslide', 'street', 'A half-cab entry into a boardslide. The 180-degree spin sets up the perpendicular slide position.', null, null, 'halfcab boardslide skateboard tutorial'),
('Kickflip Lipslide', 'street', 'A kickflip over the rail into a lipslide position. Requires the board to flip and then land across the obstacle.', null, null, 'kickflip lipslide skateboard tutorial'),
('Heelflip Lipslide', 'street', 'A heelflip into a lipslide. The heel flick must be timed perfectly to set up the slide position.', null, null, 'heelflip lipslide skateboard'),
('Nollie Boardslide', 'street', 'A boardslide entered from nollie stance. The nose is popped to launch into the perpendicular slide.', null, null, 'nollie boardslide skateboard tutorial'),
('Fakie Boardslide', 'street', 'A boardslide entered while rolling fakie. The reverse approach creates unique spatial challenges.', null, null, 'fakie boardslide skateboard tutorial'),
('360 Nosegrind', 'street', 'A 360 rotation into a nosegrind. Either the body or board completes a full spin before locking into the grind.', null, null, '360 nosegrind skateboard tutorial'),
('360 Flip Nosegrind', 'street', 'A 360 flip (tre flip) into a nosegrind. One of the most technical ledge tricks combining the iconic flip with a precise grind entry.', null, null, '360 flip nosegrind skateboard'),
('Tre Flip Crooked Grind', 'street', 'A 360 flip into a crooked grind. An extremely technical trick combining two very demanding tricks.', null, null, 'tre flip crooked grind skateboard'),
('Wallie', 'street', 'The skater rides at a wall, presses their front truck or nose against it, and uses the wall to pop off and continue skating. An old-school-influenced trick.', null, null, 'how to wallie skateboard tutorial'),
('Wallie Nosegrind', 'street', 'A wallie combined with a nosegrind off a wall or curb. A creative street trick seen in creative skating lines.', null, null, 'wallie nosegrind skateboard tutorial'),
('Manny Pad 50-50', 'street', 'A 50-50 grind on a manual pad, an obstacle specifically designed for manuals and grinds at low height. A staple of skatepark and street plaza skating.', null, null, '50-50 grind manual pad skateboard'),
('Waxed Curb Slide', 'street', 'Any slide trick performed on a waxed concrete curb. Curb skating was foundational to street skating culture in the 1980s and 1990s.', null, null, 'curb slide skateboard tricks tutorial'),
('Kinked Rail Boardslide', 'rails', 'A boardslide on a rail with one or more kinks (changes in angle). The skater must adjust position mid-slide to follow the kink.', null, null, 'kinked rail boardslide skateboard'),
('Handrail Nosegrind', 'rails', 'A nosegrind on a handrail, typically on stairs. A highly technical and dangerous trick requiring precise lock-in.', null, null, 'handrail nosegrind skateboard'),
('Handrail 50-50', 'rails', 'A 50-50 grind on a stair handrail. One of the classic rail tricks in street skating since the late 1980s.', null, null, 'handrail 50-50 grind skateboard'),
('Pole Jam', 'street', 'The skater rides up a pole or post at an angle to pop off it. A creative street trick used in lines with urban architecture.', null, null, 'pole jam skateboard trick tutorial'),
('Bench Noseslide', 'street', 'A noseslide on a park bench or similar ledge. Benches are classic street skating obstacles since the 1980s.', null, null, 'bench noseslide skateboard tutorial'),
('McTwist', 'vert', 'A 540-degree frontside inverted aerial (backside 540 with a backflip element) invented by Mike McGill in 1984 at a Swedish skate camp. One of the most celebrated tricks in vert history.', 'Mike McGill', 1984, 'McTwist skateboard vert trick Mike McGill'),
('900', 'vert', 'Two and a half aerial rotations (900 degrees). Tony Hawk became the first to land it in competition at the X Games in 1999 after years of attempts.', 'Tony Hawk', 1999, 'Tony Hawk 900 first ever X Games 1999'),
('720', 'vert', 'Two full aerial rotations (720 degrees). First landed by Tony Hawk in the early 1980s and later refined by many vert skaters.', 'Tony Hawk', 1985, '720 skateboard vert trick tutorial'),
('540', 'vert', 'One and a half aerial rotations. A foundational spin trick on vert that bridged the gap between 360s and 720s.', null, null, '540 skateboard vert trick tutorial'),
('360 Aerial', 'vert', 'A full 360-degree spin done in the air above the coping on a vert ramp. A foundational vert trick from the early 1980s.', null, null, '360 aerial vert skateboard trick'),
('Indy Backside Air', 'vert', 'A backside air with an Indy grab (back hand grabs between the feet on the toe edge). The Indy grab was named after Independent Trucks, the sponsor of its inventor.', null, null, 'indy grab backside air vert skateboard'),
('Frontside Air', 'vert', 'A basic vert trick where the skater launches frontside off the lip of the ramp and grabs the board while rotating 180 degrees frontside. A classic since the 1970s.', null, null, 'frontside air vert skateboard tutorial'),
('Backside Air', 'vert', 'The skater launches backside off the coping, grabs the board, and re-enters going the same direction. A foundational vert trick.', null, null, 'backside air vert skateboard tutorial'),
('Eggplant', 'vert', 'An inverted frontside aerial where the skater grabs the board and plants their hand on the coping. Invented by Steve Caballero, the name references its unusual shape.', 'Steve Caballero', 1981, 'eggplant trick vert skateboard'),
('Andrecht Invert', 'vert', 'A frontside invert where the back hand grabs the heel edge and the other hand is planted on the coping. Named after Dave Andrecht.', 'Dave Andrecht', 1978, 'andrecht invert skateboard vert trick'),
('Elguerial', 'vert', 'A frontside invert 540 combined into a single motion. Invented by Eddie Elguera in 1981 and considered a landmark trick in vert history.', 'Eddie Elguera', 1981, 'elguerial skateboard vert trick'),
('Miller Flip', 'vert', 'A frontside invert where the skater rotates the board 360 degrees while inverted. Invented by Darrell Miller.', 'Darrell Miller', 1981, 'miller flip vert skateboard invert'),
('Layback Air', 'vert', 'The skater leans back dramatically and slides their hand along the coping while keeping speed. An old school vert and pool trick from the 1970s.', null, null, 'layback air vert skateboard trick'),
('Layback Grind', 'vert', 'A backside grind where the skater is laid back with their hand on the coping. A stylish old school trick from pool skating.', null, null, 'layback grind skateboard pool trick'),
('Handplant', 'vert', 'A general term for tricks where the skater balances on their hand on the coping of a ramp or pool. A foundational family of vert tricks.', null, null, 'handplant skateboard vert tutorial'),
('One-Handed Handplant', 'vert', 'A handplant performed on only one hand, requiring exceptional balance and upper body strength. An advanced variation of the standard handplant.', null, null, 'one-handed handplant skateboard vert'),
('Gymnast Plant', 'vert', 'A handplant where both hands are placed on the coping and the skater balances in a gymnastics-style handstand position briefly.', null, null, 'gymnast plant skateboard vert trick'),
('Ho Ho Plant', 'vert', 'Both hands are planted on the coping while the board is pushed up in the air. An extremely rare and comedic-looking vert trick.', null, null, 'ho ho plant skateboard vert trick'),
('Christ Air', 'vert', 'Invented by Christian Hosoi, the skater extends both arms out to the side while holding the board with both hands under each arm, resembling a crucifixion pose.', 'Christian Hosoi', 1984, 'christ air skateboard trick Christian Hosoi'),
('Rocket Air', 'vert', 'Both feet are placed on the nose of the board while airborne, pointing the tail of the board straight down like a rocket. A showstopping vert trick.', null, null, 'rocket air vert skateboard trick'),
('Madonna', 'vert', 'Invented by Tony Hawk, the front foot is kicked off the nose while the back foot remains on the tail. Named by Stacy Peralta after the pop star.', 'Tony Hawk', 1984, 'madonna skateboard trick vert Tony Hawk'),
('Seatbelt Grab', 'vert', 'The back hand reaches across to grab the toe edge of the board near the front. The crossing motion resembles fastening a seatbelt.', null, null, 'seatbelt grab skateboard vert trick'),
('Japan Air', 'vert', 'The front hand grabs the heel edge of the board between the feet while both knees are bent up, creating a compact pose inspired by Japanese art.', null, null, 'japan air skateboard grab vert trick'),
('Stalefish', 'vert', 'The back hand grabs the heel edge of the board between the feet. Invented by Tony Hawk and named after a stale Swedish fish pastry.', 'Tony Hawk', 1984, 'stalefish grab skateboard vert trick'),
('Mute Grab', 'vert', 'The front hand grabs the toe edge of the board between the feet. Named because the trick''s inventor felt it was so obvious it was ''mute'' or silent in innovation.', 'Chris Weddle', 1983, 'mute grab skateboard trick tutorial'),
('Indy Grab', 'vert', 'The back hand grabs the toe edge of the board between the feet. Named after Independent Trucks by Duane Peters, one of the most widely used grabs in skateboarding.', 'Ted Nugent (attributed to team)', 1977, 'indy grab skateboard tutorial'),
('Melon Grab', 'vert', 'The front hand grabs the heel edge between the feet. Named by Neil Blender after a melon shape the body forms. A classic vert grab.', 'Neil Blender', 1983, 'melon grab skateboard trick tutorial'),
('Tail Grab', 'vert', 'The back hand reaches back and grabs the tail of the board. A simple and clean grab popular in both vert and park skating.', null, null, 'tail grab skateboard trick tutorial'),
('Nose Grab', 'vert', 'The front hand reaches forward and grabs the nose of the board. A clean and stylish grab often combined with extension tricks.', null, null, 'nose grab skateboard trick tutorial'),
('Lien Air', 'vert', 'The front hand grabs the heel edge while leaning into the backside of the ramp. ''Lien'' is ''Neil'' spelled backward, attributed to Neil Blender.', 'Neil Blender', 1983, 'lien air skateboard vert grab trick'),
('Benihana', 'vert', 'Invented by Lester Kasai, the back foot is removed from the board and held while the hand grabs the board. Named after the Japanese restaurant chain.', 'Lester Kasai', 1986, 'benihana skateboard trick vert'),
('Stiffy', 'vert', 'The legs are straightened out completely during a grab. Any grab can become a stiffy by fully extending the legs, creating a rigid, dramatic silhouette.', null, null, 'stiffy grab skateboard vert trick'),
('Slob Air', 'vert', 'A mute grab with the board twisted frontside. The term ''slob'' comes from the laid-back posture the grab creates.', null, null, 'slob air skateboard grab trick'),
('Crail Grab', 'vert', 'The back hand grabs the nose of the board while the legs are extended. A cross-body grab requiring flexibility and control.', null, null, 'crail grab skateboard trick'),
('Crossbone', 'vert', 'A mute or indy grab where the grabbing arm is extended and crossed over the front of the body. Creates a dramatic crossed-arm visual.', null, null, 'crossbone grab skateboard trick'),
('Gorilla Grip', 'vert', 'Both hands are used to grab the board with an overhand grip on the rails. An unusual and dramatic grab style.', null, null, 'gorilla grip grab skateboard trick'),
('Kickflip McTwist', 'vert', 'A McTwist (540 inverted aerial) combined with a kickflip. An extremely rare and advanced vert trick.', null, null, 'kickflip mctwist vert skateboard'),
('Varial McTwist', 'vert', 'A McTwist with a varial flip added. One of the rarest vert trick combinations.', null, null, 'varial mctwist vert skateboard'),
('Heelflip Varial Lien', 'vert', 'A heelflip varial combined with a lien grab. A technical combination trick mixing flip tricks with vert grab mechanics.', null, null, 'heelflip varial lien skateboard vert'),
('Kickflip to Fakie', 'vert', 'A kickflip performed on the vert ramp that lands fakie (rolling backward). Adapts street flat-ground tricks to vert transition.', null, null, 'kickflip to fakie vert skateboard tutorial'),
('Ollie to Fakie', 'vert', 'An ollie on the vert ramp that lands fakie. One of the foundational transition tricks for learning to ride fakie on vert.', null, null, 'ollie to fakie vert skateboard tutorial'),
('Rock to Fakie', 'vert', 'The front truck rocks on the coping briefly and then comes back down fakie. One of the first tricks beginner vert skaters learn.', null, null, 'how to rock to fakie skateboard tutorial'),
('Rock and Roll', 'vert', 'The front truck rocks on the coping and then the skater rotates frontside to come back in. A classic vert and mini-ramp trick.', null, null, 'how to rock and roll skateboard ramp tutorial'),
('Disaster', 'vert', 'The board is ollied to 180 degrees so that the center of the board lands on the coping, then the skater rolls back in. A quirky old-school ramp trick.', null, null, 'how to disaster skateboard ramp tutorial'),
('Blunt to Fakie', 'vert', 'The tail is stalled on the coping while the nose is elevated, then the skater rolls back fakie. A classic ramp trick requiring commitment.', null, null, 'how to blunt to fakie skateboard tutorial'),
('Kickturn', 'vert', 'The front trucks are lifted and the board pivots on the back trucks to change direction. The most basic vert/ramp maneuver and the foundation of all ramp skating.', null, null, 'how to kickturn skateboard ramp tutorial'),
('Frontside Rock and Roll', 'vert', 'A rock and roll done frontside. The skater must lean into the frontside rotation to re-enter the ramp.', null, null, 'frontside rock and roll skateboard tutorial'),
('Backside Disaster', 'vert', 'A disaster approached from the backside. The 180-degree rotation goes backside before the board balances on the coping.', null, null, 'backside disaster skateboard ramp tutorial'),
('Inverted Aerial', 'vert', 'Any trick where the skater goes upside-down above the coping while performing a grab. A whole family of classic vert tricks from the 1970s-80s.', null, null, 'inverted aerial skateboard vert trick'),
('Invert', 'vert', 'A one-handed handplant where the back hand grabs the heel edge while the other hand is planted on the coping. A foundational vert invert trick.', null, null, 'how to invert skateboard vert tutorial'),
('Sad Plant', 'vert', 'A handplant where the front foot is removed from the board and placed on the coping while the skater is inverted. A creative variation on standard handplants.', null, null, 'sad plant skateboard vert trick'),
('Nosebonk', 'vert', 'The nose of the board taps or bonks off an obstacle, wall, or the coping while airborne. A playful and creative trick.', null, null, 'nosebonk skateboard trick'),
('Tailbonk', 'vert', 'The tail taps off an obstacle while airborne. The counterpart to the nosebonk.', null, null, 'tailbonk skateboard trick'),
('Frontside Blunt', 'vert', 'A blunt stall approached frontside on a vert ramp or mini ramp. The tail locks on the coping with the body facing out.', null, null, 'frontside blunt skateboard ramp tutorial'),
('Backside Blunt', 'vert', 'A blunt stall approached backside. Requires the back to face the coping during the stall.', null, null, 'backside blunt skateboard ramp tutorial'),
('Alley-oop', 'vert', 'Any trick where the spin direction is opposite to the direction of travel. Used to add style and difficulty to standard spins on vert.', null, null, 'alley oop skateboard vert trick'),
('Cess Slide', 'vert', 'A slide performed on the face of the ramp below the coping, rather than on the coping itself. An old school pool and vert trick.', null, null, 'cess slide skateboard pool trick'),
('K-Grind', 'street', 'An alternative name for the crooked grind, named because the grind position resembles the letter K. Very common in tech street skating.', null, null, 'k grind crooked grind skateboard tutorial'),
('Lipslide Shove-it Out', 'street', 'A lipslide where the exit is a pop shove-it, rotating the board 180 degrees to exit. A stylish way to end a lipslide.', null, null, 'lipslide shove it out skateboard'),
('Noseslide Shove-it Out', 'street', 'A noseslide that exits with a shove-it, adding a 180-degree board rotation to the dismount.', null, null, 'noseslide shove it out skateboard'),
('Backside Noseblunt Slide', 'street', 'A noseblunt slide approached from the backside. A very technical and rarely attempted variation.', null, null, 'backside noseblunt slide skateboard'),
('Switch Blunt Slide', 'street', 'A blunt slide performed in switch stance. Extremely technical and rare in street skating.', null, null, 'switch blunt slide skateboard'),
('Manual', 'street', 'Balancing on the back two wheels while rolling. The skateboarding version of a wheelie. A fundamental skill that underpins countless combo tricks.', null, null, 'how to manual skateboard tutorial beginner'),
('Nose Manual', 'street', 'Balancing on the front two wheels while rolling. Also called a nose wheelie. More difficult to control than a regular manual due to the nose weight.', null, null, 'how to nose manual skateboard tutorial'),
('One Wheel Manual', 'street', 'Balancing on only one wheel (back right or back left) while rolling. Requires extreme balance and is considered a freestyle feat.', null, null, 'one wheel manual skateboard trick'),
('Nose Manual Kickflip Out', 'street', 'A nose manual that exits with a kickflip. A classic tech combo trick combining a sustained manual with a flip exit.', null, null, 'nose manual kickflip out skateboard tutorial'),
('Manual Kickflip Out', 'street', 'A manual that ends with a kickflip. One of the most common manual combo tricks in street skating.', null, null, 'manual kickflip out skateboard tutorial'),
('Manual Heelflip Out', 'street', 'A manual exited with a heelflip. Requires maintaining balance through the manual before executing the flip.', null, null, 'manual heelflip out skateboard tutorial'),
('Nose Manual Heelflip Out', 'street', 'A nose manual that exits with a heelflip. A technical combo requiring balance and precise foot placement.', null, null, 'nose manual heelflip out skateboard'),
('Manual 360 Flip Out', 'street', 'A manual with a 360 flip (tre flip) exit. An impressive and technical combo trick.', null, null, 'manual 360 flip out skateboard tutorial'),
('Nose Manual to Manual', 'street', 'Transitioning from a nose manual to a regular manual within the same combo. Requires extremely precise weight shifting.', null, null, 'nose manual to manual skateboard tutorial'),
('Kickflip Manual', 'street', 'A kickflip into a manual. The flip trick sets up the back-wheel balance position.', null, null, 'kickflip manual skateboard tutorial'),
('Heelflip Manual', 'street', 'A heelflip into a manual. A classic tech street combo trick.', null, null, 'heelflip manual skateboard tutorial'),
('360 Flip Manual', 'street', 'A 360 flip (tre flip) into a manual. One of the most technical manual entry tricks.', null, null, '360 flip manual skateboard tutorial'),
('Varial Kickflip Manual', 'street', 'A varial kickflip into a manual. An intermediate-level tech combo.', null, null, 'varial kickflip manual skateboard tutorial'),
('Casper Stall', 'freestyle', 'The board is balanced on its nose (or tail) with the grip tape facing up while the skater''s foot holds it in place. Named after Bobby ''Casper'' Boyden.', 'Bobby Boyden', 1975, 'casper stall skateboard freestyle trick'),
('Rail Stand', 'freestyle', 'The board is balanced vertically on one of its rails (side edges) while the skater stands on it. A classic Rodney Mullen freestyle trick.', 'Rodney Mullen', 1982, 'rail stand skateboard freestyle trick Rodney Mullen'),
('Pogo', 'freestyle', 'The board is stood on its tail and the skater bounces on it like a pogo stick. A classic freestyle trick popularized in the early 1980s.', null, null, 'pogo skateboard freestyle trick'),
('Primo', 'freestyle', 'The board is balanced on its side (one rail and one wheel) while the skater balances on it. Named after professional skater Primo Desiderio.', 'Primo Desiderio', 1980, 'primo balance skateboard freestyle trick'),
('Headstand', 'freestyle', 'The skater balances on their head on the board while rolling. An extremely rare and gymnastic trick from the early days of freestyle skating.', null, null, 'headstand skateboard freestyle trick'),
('360 Shove-it Casper', 'freestyle', 'A 360 shove-it that lands in a Casper (upside-down board) position. Combines a spin trick with a balance trick in one fluid motion.', 'Rodney Mullen', 1983, '360 shove it casper skateboard freestyle'),
('One-Foot Manual', 'freestyle', 'A manual performed with only one foot on the board. A freestyle trick requiring exceptional balance.', null, null, 'one foot manual skateboard freestyle'),
('No-Handed 50-50', 'freestyle', 'Performing a 50-50 grind without using hands for balance or assistance. A refined version of the standard grind emphasizing pure skill.', null, null, 'no-handed 50-50 skateboard freestyle'),
('Helipop', 'freestyle', 'A nollie 360 backside shove-it combined with a flip. A freestyle trick that Rodney Mullen brought into street skating.', 'Rodney Mullen', 1984, 'helipop skateboard freestyle trick'),
('Casper Slide', 'freestyle', 'Sliding on the grip tape with the board upside down (Casper position). An advanced freestyle sliding trick.', null, null, 'casper slide skateboard freestyle trick'),
('Anti Casper', 'freestyle', 'A variation of the Casper where the board is flipped the other direction. An obscure freestyle trick rarely performed outside of dedicated freestyle competitions.', null, null, 'anti casper skateboard freestyle trick'),
('Endover', 'freestyle', 'A continuous series of 180-degree pivots alternating between nose and tail, creating a walking motion. A fundamental freestyle move from the 1960s.', null, null, 'endover skateboard freestyle trick tutorial'),
('Spinner', 'freestyle', 'A flatground 360-degree body spin performed without lifting the board off the ground. An early freestyle fundamental trick.', null, null, 'spinner skateboard freestyle trick'),
('Coffin', 'freestyle', 'The skater lies flat on their back on the board while rolling. A classic old-school trick that requires balance and fearlessness.', null, null, 'coffin skateboard trick tutorial'),
('Footplant', 'freestyle', 'The skater plants one or both feet on the ground temporarily while doing a trick. A broad family of tricks popularized in both freestyle and early street skating.', null, null, 'footplant skateboard trick tutorial'),
('Darkslide Manual', 'freestyle', 'Balancing in a manual while the board is flipped upside down (grip tape down). An incredibly difficult trick blending Rodney Mullen''s darkslide concept with manual balance.', 'Rodney Mullen', 1996, 'darkslide manual skateboard Rodney Mullen'),
('Switchfoot 360 Shove-it', 'freestyle', 'A 360 shove-it where the skater switches from regular to switch stance during the trick. A Rodney Mullen specialty combining footwork with board tricks.', 'Rodney Mullen', 1985, 'switchfoot 360 shove it skateboard Rodney Mullen'),
('360 Casper', 'freestyle', 'The board rotates 360 degrees while in Casper (upside-down) position. An advanced freestyle combination trick.', null, null, '360 casper skateboard freestyle'),
('G-Turn', 'freestyle', 'A frontside 360-degree turn performed by pumping the board with alternating weight shifts rather than an ollie. A flowing old-school freestyle maneuver.', null, null, 'G-turn skateboard freestyle trick'),
('Ollie Impossible Shove-it', 'freestyle', 'An impossible combined with a shove-it. The board wraps around the foot and rotates simultaneously. An extremely obscure Rodney Mullen-style combination.', 'Rodney Mullen', 1986, 'impossible shove it skateboard freestyle'),
('Handstand', 'freestyle', 'The skater performs a handstand on the board while rolling. A gymnastic trick from the earliest days of freestyle skateboarding.', null, null, 'handstand skateboard freestyle trick'),
('Sit Down', 'freestyle', 'The skater sits down on the board while rolling, then stands back up. A casual-looking trick requiring precise balance.', null, null, 'sit down skateboard trick freestyle'),
('Gorilla Grip Walk', 'freestyle', 'The skater grabs the board with both hands overhand while rolling and walks alongside the board. An old school freestyle exhibition move.', null, null, 'gorilla grip walk skateboard freestyle'),
('Spacewalk', 'freestyle', 'A continuous slalom-style weaving trick where the skater shifts weight side to side rhythmically. Associated with freestyle and longboard dancing.', null, null, 'spacewalk skateboard freestyle longboard trick'),
('Tiger Claw', 'freestyle', 'The back foot kicks the tail of the board up, the front hand catches it mid-air, and then the board is placed back under the feet. A unique Rodney Mullen freestyle trick.', 'Rodney Mullen', 1984, 'tiger claw skateboard trick Rodney Mullen'),
('Kick Nose Manual', 'freestyle', 'The skater kicks the board forward into a nose manual position without an ollie entry. A flow-based freestyle manual technique.', null, null, 'kick nose manual skateboard freestyle'),
('Foot Drag', 'freestyle', 'One foot drags on the ground to slow down or control direction while the other foot remains on the board. Used for speed control and style.', null, null, 'foot drag skateboard freestyle'),
('Two-Foot Walk', 'freestyle', 'The skater alternates between placing each foot on the ground while the board rolls underneath. A walking illusion trick.', null, null, 'two foot walk skateboard freestyle trick'),
('540 Shove-it', 'freestyle', 'The board rotates 540 degrees (one and a half rotations) while the skater ollies. A more extreme version of the 360 shove-it.', null, null, '540 shove it skateboard trick tutorial'),
('720 Shove-it', 'freestyle', 'The board rotates 720 degrees (two full rotations) from a shove-it motion. Extremely rare and requires significant height to complete.', null, null, '720 shove it skateboard trick'),
('Ollie One-Footer', 'flatground', 'After an ollie, one foot is kicked off the board while the other foot maintains contact. A stylish old-school extension trick.', null, null, 'ollie one footer skateboard trick tutorial'),
('Ollie Impossible to Manual', 'freestyle', 'An impossible trick that lands in a manual. A Rodney Mullen-inspired combination of two of his signature tricks.', 'Rodney Mullen', 1986, 'impossible to manual skateboard combo'),
('Nose Manual 360 Flip Out', 'street', 'A nose manual that exits with a 360 flip. One of the most technically demanding manual combo tricks.', null, null, 'nose manual 360 flip out skateboard'),
('Kickflip to Noseslide', 'street', 'A kickflip that lands in a noseslide position. Requires the board to flip and then the nose to lock onto the obstacle.', null, null, 'kickflip noseslide skateboard tutorial'),
('Heelflip to Noseslide', 'street', 'A heelflip entry into a noseslide. The heel flick must be controlled enough to align the nose for the slide.', null, null, 'heelflip noseslide skateboard tutorial'),
('360 Flip to Boardslide', 'street', 'A 360 flip that lands in a boardslide position. The combination of the spinning flip and the perpendicular landing makes this extremely difficult.', null, null, '360 flip boardslide skateboard'),
('Pool Carve', 'bowl', 'Flowing through a bowl or pool using continuous carving turns. The most fundamental skill in pool and bowl skateboarding, dating to the earliest skatepark era of the 1970s.', null, null, 'pool carve skateboard bowl skating technique'),
('Frontside Grind (Pool)', 'bowl', 'A 50-50 or 5-0 grind performed frontside on pool coping. Grinding pool coping is a defining skill of bowl skateboarding.', null, null, 'frontside grind pool skateboard bowl'),
('Backside Grind (Pool)', 'bowl', 'A grind on pool coping approached from the backside. The original backside grinds were pioneered by pool skaters in the late 1970s.', null, null, 'backside grind pool skateboard bowl tutorial'),
('Poolside Ollie', 'bowl', 'An ollie above the pool coping, clearing the lip and returning to the pool. A fundamental aerial skill in pool and bowl skating.', null, null, 'ollie above lip pool skateboard bowl'),
('Bowl Slash Grind', 'bowl', 'A carving grind where the back truck slashes across the coping at an angle. A classic aggressive bowl-skating grind.', null, null, 'slash grind bowl pool skateboard'),
('Coping Grind', 'bowl', 'A general grind on the rounded or square coping that tops a pool or bowl. The coping of a pool was the original grinding obstacle in skateboarding.', null, null, 'coping grind skateboard bowl pool tutorial'),
('Lip Trick', 'bowl', 'A broad category of tricks performed on or above the coping lip of a pool or bowl. Includes stalls, grinds, and slides on pool coping.', null, null, 'lip tricks bowl skateboard pool tutorial'),
('Egg Bowl', 'bowl', 'Crouching into a tight ball while carving a pool or bowl to gain speed and create a dramatic visual. Inspired by egg-crouch techniques from snowboarding.', null, null, 'egg carve bowl pool skateboard technique'),
('Frontside Nosegrind (Bowl)', 'bowl', 'A nosegrind on bowl coping approached frontside. Adapts the street nosegrind to pool/bowl coping.', null, null, 'frontside nosegrind bowl pool skateboard'),
('Backside Smith (Bowl)', 'bowl', 'A Smith grind on pool coping approached from the backside. Requires aggressive commitment to lock the back truck below the coping.', null, null, 'backside smith grind pool bowl skateboard'),
('Tuck Knee Invert', 'bowl', 'A handplant invert where one knee is tucked into the chest while inverted. A classic pool trick with strong visual impact.', null, null, 'tuck knee invert skateboard pool bowl'),
('Pool Ollie North', 'bowl', 'An ollie over the lip of a pool with the front foot kicked forward off the nose while airborne. A stylish extension of the ollie north in pool context.', null, null, 'ollie north pool skateboard trick'),
('Pool 50-50 Revert', 'bowl', 'A 50-50 grind on pool coping that exits with a 180-degree revert. A smooth way to change direction after a grind.', null, null, '50-50 revert pool skateboard bowl'),
('Alley-oop Frontside Air', 'bowl', 'A frontside air performed in the alley-oop direction (against the natural rotation direction). A challenging and stylish pool trick.', null, null, 'alley oop frontside air pool skateboard'),
('Full Pipe Run', 'bowl', 'Skating through a fully enclosed cylindrical concrete pipe, performing tricks on the walls and ceiling. A unique skateboarding format from the early 1970s.', null, null, 'full pipe skateboarding run tricks'),
('Boneless', 'vert', 'The front foot is grabbed and planted on the ground while the board is held, then the skater remounts and lands. Invented by Steve Olson, popularized in the 1980s.', 'Steve Olson', 1979, 'boneless skateboard trick tutorial'),
('Boneless One', 'vert', 'A boneless where only one foot plants while the grab and re-mounting happen quickly. A specific variation of the boneless family of tricks.', null, null, 'boneless one skateboard trick'),
('Frontside Boneless', 'vert', 'A boneless done with a frontside rotation. The skater plants and rotates frontside before landing.', null, null, 'frontside boneless skateboard trick'),
('One-Foot Ollie', 'flatground', 'An ollie performed with only one foot on the board, the other hanging free. A style trick demonstrating control and pop.', null, null, 'one foot ollie skateboard trick tutorial'),
('Nollie 360 Backside Flip', 'flatground', 'A nollie backside 360 flip - combining nollie stance with the 360 flip rotation going backside. One of the rarest nollie combinations.', null, null, 'nollie backside 360 flip skateboard'),
('Fakie 360 Backside Flip', 'flatground', 'A backside 360 flip from fakie stance. The reverse riding adds a layer of complexity to the already demanding trick.', null, null, 'fakie backside 360 flip skateboard'),
('Switch Varial Kickflip', 'flatground', 'A varial kickflip in switch stance. The pop shove-it and kickflip are both executed with the non-dominant foot leading.', null, null, 'switch varial kickflip skateboard'),
('Nollie Laser Flip', 'flatground', 'A laser flip (frontside 360 heel) from nollie stance. Among the rarest and most technical nollie flip tricks.', null, null, 'nollie laser flip skateboard'),
('Switch Laser Flip', 'flatground', 'A laser flip performed in switch stance. One of the most technical switch flip tricks known.', null, null, 'switch laser flip skateboard'),
('Fakie Big Flip', 'flatground', 'A big flip (backside 360 body rotation with kickflip) from fakie stance. An advanced fakie combination.', null, null, 'fakie big flip skateboard tutorial'),
('Nollie Big Flip', 'flatground', 'A big flip from nollie stance. A rare and technical nollie spin-flip combination.', null, null, 'nollie big flip skateboard tutorial'),
